parameters.jsCode:
let eth_balance = 0;
let polygon_balance = 0;
let eth_gas = 0;
let polygon_gas = 0;
let coins = [];

for (const item of items) {

  const data = item.json;

  // ETH Balance
  if (data.network === "ethereum-mainnet" && data.balanceEth !== undefined) {
    eth_balance = Number(data.balanceEth);
  }

  // Polygon Balance
  if (data.network === "polygon-mainnet" && data.balanceEth !== undefined) {
    polygon_balance = Number(data.balanceEth);
  }

  // ETH Gas
  if (data.network === "ethereum-mainnet" && data.gasPriceGwei !== undefined) {
    eth_gas = Number(data.gasPriceGwei);
  }

  // Polygon Gas
  if (data.network === "polygon-mainnet" && data.gasPriceGwei !== undefined) {
    polygon_gas = Number(data.gasPriceGwei);
  }

  // ✅ Get coins dynamically
  if (data.coins) {
    coins = data.coins;
  }
}

return [{
  json: {
    eth_balance,
    polygon_balance,
    eth_gas,
    polygon_gas,
    coins
  }
}];

const data = $json;

// Prices
const eth_price = data.ETH?.USD || 0;
const matic_price = data.MATIC?.USD || 0;

// Balances
const eth_balance = data.eth_balance || 0;
const matic_balance = data.polygon_balance || 0;

// Gas
const eth_gas = data.eth_gas || 0;
const matic_gas = data.polygon_gas || 0;

// USD values
const eth_value = eth_balance * eth_price;
const matic_value = matic_balance * matic_price;

const total = eth_value + matic_value;

// Allocation %
const eth_pct = total ? (eth_value / total) * 100 : 0;
const matic_pct = total ? (matic_value / total) * 100 : 0;

return [{
  json: {
    eth_balance,
    matic_balance,
    eth_price,
    matic_price,
    eth_gas,
    matic_gas,
    eth_value,
    matic_value,
    total,
    eth_pct,
    matic_pct
  }
}];

